// Two-branch parallel agent extraction — one item per county. Each county's
// agent call gets its own credit budget, so a Lee scrape failure can't
// silently consume the Collier budget too.
return [
  {
    json: {
      county: 'Lee',
      urls: [
        'https://www.leegov.com/dcd/planning',
        'https://www.leegov.com/dcd/zoning'
      ]
    }
  },
  {
    json: {
      county: 'Collier',
      urls: [
        'https://www.colliercountyfl.gov/your-government/divisions-a-e/development-review',
        'https://www.colliercountyfl.gov/your-government/divisions-a-e/zoning'
      ]
    }
  }
];

parameters.jsonBody:
={
  "urls": {{ JSON.stringify($json.urls) }},
  "strictConstrainToURLs": false,
  "prompt": "Extract recent planning commission and zoning board decisions for {{ $json.county }} County, Florida. For each decision, return: decision_date (ISO YYYY-MM-DD), decision_type (one of: approved, denied, deferred, withdrawn, continued), location (address or parcel), description (1-2 sentence summary), source_url (link to the staff report or agenda item PDF). Include only decisions issued in the last 90 days. Use null when a field is not available — never invent.",
  "schema": {
    "type": "object",
    "properties": {
      "rows": {
        "type": "array",
        "items": {
          "type": "object",
          "properties": {
            "decision_date":  { "type": ["string", "null"], "pattern": "^\\d{4}-\\d{2}-\\d{2}$" },
            "decision_type":  { "type": ["string", "null"] },
            "location":       { "type": ["string", "null"] },
            "description":    { "type": ["string", "null"] },
            "source_url":     { "type": ["string", "null"] }
          }
        }
      }
    }
  },
  "model": "spark-1-mini",
  "maxCredits": 1500
}

parameters.jsCode:
const now      = new Date();
const iso      = now.toISOString();
const yyyy     = String(now.getUTCFullYear());
const mm       = String(now.getUTCMonth() + 1).padStart(2, '0');
const decisions = [];
for (const item of items) {
  const county = item.json?.county ?? null;
  const root   = item.json?.data?.result ?? item.json?.result ?? item.json;
  const rows   = Array.isArray(root?.rows) ? root.rows : [];
  for (const r of rows) {
    decisions.push({
      county,
      decision_date:  r.decision_date ?? null,
      decision_type:  r.decision_type ?? null,
      location:       r.location ?? null,
      description:    r.description ?? null,
      source_url:     r.source_url ?? null,
      _ingested_at:   iso
    });
  }
}
if (decisions.length === 0) {
  throw new Error('Flow 5: zero decisions across both counties — investigate.');
}
const ndjson = decisions.map(d => JSON.stringify(d)).join('\n') + '\n';
const bytes  = Buffer.byteLength(ndjson, 'utf-8');
const path   = `county-planning/year=${yyyy}/month=${mm}/lee-collier-${iso}.ndjson`;
return [{
  json: {
    bucket:    'lake-tier1',
    path,
    full_id:   `lake-tier1/${path}`,
    vintage:   `${yyyy}-${mm}-01`,
    byte_size: bytes,
    body:      ndjson,
    decision_count: decisions.length
  }
}];
